export function Entity(
    nameOrOptions?: string | EntityOptions,
    maybeOptions?: EntityOptions,
): ClassDecorator {
    const options =
        (ObjectUtils.isObject(nameOrOptions)
            ? (nameOrOptions as EntityOptions)
            : maybeOptions) ?? {}
    const name =
        typeof nameOrOptions === "string" ? nameOrOptions : options.name

    return function (target) {
        getMetadataArgsStorage().tables.push({
            target: target,
            name: name,
            type: "regular",
            orderBy: options.orderBy ?? undefined,
            engine: options.engine ?? undefined,
            database: options.database ?? undefined,
            schema: options.schema ?? undefined,
            synchronize: options.synchronize,
            withoutRowid: options.withoutRowid,
            comment: options.comment ?? undefined,
        } as TableMetadataArgs)
    }
}

export function ViewEntity(
    nameOrOptions?: string | ViewEntityOptions,
    maybeOptions?: ViewEntityOptions,
): ClassDecorator {
    const options =
        (ObjectUtils.isObject(nameOrOptions)
            ? (nameOrOptions as ViewEntityOptions)
            : maybeOptions) ?? {}
    const name =
        typeof nameOrOptions === "string" ? nameOrOptions : options.name

    return function (target: Function) {
        getMetadataArgsStorage().tables.push({
            target: target,
            name: name,
            expression: options.expression,
            dependsOn: options.dependsOn
                ? new Set(options.dependsOn)
                : undefined,
            type: "view",
            database: options.database ?? undefined,
            schema: options.schema ?? undefined,
            synchronize: options.synchronize === false ? false : true,
            materialized: !!options.materialized,
        } as TableMetadataArgs)
    }
}

