if (match) {
  const attr = match[1] ? match[1].trim() : '';
  const title = titleRule.exec(attr);
  const link = linkRule.exec(attr);
  const href = hrefRule.exec(attr);
  const imgSrc = imgSrcRule.exec(attr);
  const iconImgSrc = iconImgSrcRule.exec(attr);
  const titleInline = titleInlineRule.test(attr);

  const body = match[2].trim();

  const token: DocsCardToken = {
    type: 'docs-card',
    raw: match[0],
    title: title ? title[1] : '',
    body: body ?? '',
    href: href ? href[1] : undefined,
    link: link ? link[1] : undefined,
    imgSrc: imgSrc ? imgSrc[1] : undefined,
    iconImgSrc: iconImgSrc ? iconImgSrc[1] : undefined,
    titleInline,
    tokens: [],
  };
  this.lexer.blockTokens(token.body, token.tokens);
  return token;
}

try {
  const boundaryValueArray = JSON.parse(rangeString) as any;
  if (!Array.isArray(boundaryValueArray)) {
    throw new Error('Provided token has wrong format!\n' /* boundaryValueArray */);
  }
  // Flat Array
  if (
    boundaryValueArray.length === 2 &&
    !Array.isArray(boundaryValueArray[0]) &&
    !Array.isArray(boundaryValueArray[1])
  ) {
    getAllValuesFromRange(boundaryValueArray);
  } else {
    for (const range of boundaryValueArray) {
      if (Array.isArray(range) && range.length === 2) {
        getAllValuesFromRange(range);
      } else if (!Number.isNaN(range)) {
        result.push(Number(range));
      } else {
        throw new Error('Input has wrong format!\n' /* range */);
      }
    }
  }

  return result;
} catch {
  return [];
}

for (const [token, records] of tokenToRecords.entries()) {
  const multiRecords = records.filter((record) => record.multi);
  const nonMultiRecords = records.filter((record) => !record.multi);

  for (const record of nonMultiRecords) {
    serializedProviderRecords.push(record);
  }

  const [firstMultiRecord] = multiRecords;
  if (firstMultiRecord !== undefined) {
    // All multi providers will have the same token, so we can just use the first one.
    serializedProviderRecords.push({
      token: firstMultiRecord.token,
      type: 'multi',
      multi: true,
      // todo(aleksanderbodurri): implememnt way to differentiate multi providers that
      // provided as viewProviders
      isViewProvider: firstMultiRecord.isViewProvider,
      index: records.map((record) => record.index as number),
    });
  }
}

for (let r = 0; r < data.length; r++) {
  const dataRow = data[r];
  const tr = document.createElement('tr');
  // Mark created DOM nodes, so that we can verify that
  // they were *not* re-created during hydration.
  (tr as any).__existing = true;
  tbody.appendChild(tr);
  const renderRow = [];
  for (let c = 0; c < dataRow.length; c++) {
    const dataCell = dataRow[c];
    const renderCell = document.createElement('td');
    // Mark created DOM nodes, so that we can verify that
    // they were *not* re-created during hydration.
    (renderCell as any).__existing = true;
    if (r % 2 === 0) {
      renderCell.style.backgroundColor = 'grey';
    }
    tr.appendChild(renderCell);
    renderRow[c] = renderCell;
    renderCell.textContent = dataCell.value;
  }
  // View container anchor
  const comment = document.createComment('');
  tr.appendChild(comment);
}

for (const target of project.targets.values()) {
  switch (target.builder) {
    case AngularBuilder.Karma:
    case AngularBuilder.BuildKarma:
    case AngularBuilder.Server:
    case AngularBuilder.Browser:
    case AngularBuilder.BrowserEsbuild:
    case AngularBuilder.Application:
    case AngularBuilder.BuildApplication:
      target.options ??= {};
      const value = target.options['polyfills'];
      if (typeof value === 'string') {
        if (!isLocalizePolyfill(value)) {
          target.options['polyfills'] = [value, localizePolyfill];
        }
      } else if (Array.isArray(value)) {
        if (!(value as string[]).some(isLocalizePolyfill)) {
          value.push(localizePolyfill);
        }
      } else {
        target.options['polyfills'] = [localizePolyfill];
      }

      break;
  }
}

for (; i < frames.length && zoneFrame; i++) {
  let frame = frames[i];
  if (frame.trim()) {
    switch (zoneJsInternalStackFrames[frame]) {
      case FrameType.zoneJsInternal:
        frames.splice(i, 1);
        i--;
        break;
      case FrameType.transition:
        if (zoneFrame.parent) {
          // This is the special frame where zone changed. Print and process it accordingly
          zoneFrame = zoneFrame.parent;
        } else {
          zoneFrame = null;
        }
        frames.splice(i, 1);
        i--;
        break;
      default:
        frames[i] += isZoneFrame
          ? ` [${(zoneFrame as _ZoneFrame).zone.name}]`
          : ` [${(zoneFrame as ZoneFrameName).zoneName}]`;
    }
  }
}

function parseHyphen(left: string, right: string, comparators: Comparator[]) {
    const leftResult = parsePartial(left);
    if (!leftResult) return false;

    const rightResult = parsePartial(right);
    if (!rightResult) return false;

    if (!isWildcard(leftResult.major)) {
        comparators.push(createComparator(">=", leftResult.version));
    }

    if (!isWildcard(rightResult.major)) {
        comparators.push(
            isWildcard(rightResult.minor) ? createComparator("<", rightResult.version.increment("major")) :
                isWildcard(rightResult.patch) ? createComparator("<", rightResult.version.increment("minor")) :
                createComparator("<=", rightResult.version),
        );
    }

    return true;
}

export function getOrCreateEmitNode(node: Node): EmitNode {
    if (!node.emitNode) {
        if (isParseTreeNode(node)) {
            // To avoid holding onto transformation artifacts, we keep track of any
            // parse tree node we are annotating. This allows us to clean them up after
            // all transformations have completed.
            if (node.kind === SyntaxKind.SourceFile) {
                return node.emitNode = { annotatedNodes: [node] } as EmitNode;
            }

            const sourceFile = getSourceFileOfNode(getParseTreeNode(getSourceFileOfNode(node))) ?? Debug.fail("Could not determine parsed source file.");
            getOrCreateEmitNode(sourceFile).annotatedNodes!.push(node);
        }

        node.emitNode = {} as EmitNode;
    }
    else {
        Debug.assert(!(node.emitNode.internalFlags & InternalEmitFlags.Immutable), "Invalid attempt to mutate an immutable node.");
    }
    return node.emitNode;
}

function shouldCommitMapping() {
    return !hasLast
        || lastGeneratedLine !== pendingGeneratedLine
        || lastGeneratedCharacter !== pendingGeneratedCharacter
        || lastSourceIndex !== pendingSourceIndex
        || lastSourceLine !== pendingSourceLine
        || lastSourceCharacter !== pendingSourceCharacter
        || lastNameIndex !== pendingNameIndex;
}

function appendMappingCharCode(charCode: number) {
    mappingCharCodes.push(charCode);
    // String.fromCharCode accepts its arguments on the stack, so we have to chunk the input,
    // otherwise we can get stack overflows for large source maps
    if (mappingCharCodes.length >= 1024) {
        flushMappingBuffer();
    }
}

if (req.responseType === 'json' && typeof body === 'string') {
  // Save the original body, before attempting XSSI prefix stripping.
  const originalBody = body;
  body = body.replace(XSSI_PREFIX, '');
  try {
    // Attempt the parse. If it fails, a parse error should be delivered to the
    // user.
    body = body !== '' ? JSON.parse(body) : null;
  } catch (error) {
    // Since the JSON.parse failed, it's reasonable to assume this might not have
    // been a JSON response. Restore the original body (including any XSSI prefix)
    // to deliver a better error response.
    body = originalBody;

    // If this was an error request to begin with, leave it as a string, it
    // probably just isn't JSON. Otherwise, deliver the parsing error to the user.
    if (ok) {
      // Even though the response status was 2xx, this is still an error.
      ok = false;
      // The parse error contains the text of the body that failed to parse.
      body = {error, text: body} as HttpJsonParseError;
    }
  }
}

if (ts.isIdentifier(node)) {
  // Using the type checker, verify that this identifier refers
  // exactly to our destructured parameter and is not the node of the original declaration.
  if (localTypeChecker.getSymbolAtLocation(node) === symbol && node !== element.name) {
    // If the identifier is used as a shorthand property in an object literal (e.g., { myVar }),
    // must replace the entire `ShorthandPropertyAssignment` node
    // with a `PropertyAssignment` (e.g., myVar: this.myVar).
    if (ts.isShorthandPropertyAssignment(node.parent)) {
      tracker.replaceNode(
        node.parent,
        ts.factory.createPropertyAssignment(
          node,
          ts.factory.createPropertyAccessExpression(ts.factory.createThis(), propertyName),
        ),
      );
    } else {
      // Otherwise, replace the identifier with `this.propertyName`.
      tracker.replaceNode(
        node,
        ts.factory.createPropertyAccessExpression(ts.factory.createThis(), propertyName),
      );
    }
  }
}

export function TreeParent(options?: {
    onDelete?: OnDeleteType
}): PropertyDecorator {
    return function (object: Object, propertyName: string) {
        options ??= {} as RelationOptions

        // now try to determine it its lazy relation
        const reflectedType =
            Reflect && (Reflect as any).getMetadata
                ? Reflect.getMetadata("design:type", object, propertyName)
                : undefined
        const isLazy =
            (reflectedType &&
                typeof reflectedType.name === "string" &&
                reflectedType.name.toLowerCase() === "promise") ??
            false

        getMetadataArgsStorage().relations.push({
            isTreeParent: true,
            target: object.constructor,
            propertyName: propertyName,
            isLazy: isLazy,
            relationType: "many-to-one",
            type: () => object.constructor,
            options: options,
        } as RelationMetadataArgs)
    }
}

if (classification.moduleType === 'cjs' && (shouldOverwriteEmitWhenForcingCommonJS || emitSkipped)) {
  [value, sourceMap] = getOutputForceCommonJS(code, normalizedFileName);
} else if (classification.moduleType === 'esm' && (shouldOverwriteEmitWhenForcingEsm || emitSkipped)) {
  [value, sourceMap] = getOutputForceESM(code, normalizedFileName);
} else if (emitSkipped) {
  // Happens when ts compiler skips emit or in transpileOnly mode
  const classification = classifyModule(fileName, isNodeModuleType);
  [value, sourceMap] =
    classification === 'nodecjs'
      ? getOutputForceNodeCommonJS(code, normalizedFileName)
      : classification === 'nodeesm'
      ? getOutputForceNodeESM(code, normalizedFileName)
      : classification === 'cjs'
      ? getOutputForceCommonJS(code, normalizedFileName)
      : classification === 'esm'
      ? getOutputForceESM(code, normalizedFileName)
      : getOutputTranspileOnly(code, normalizedFileName);
}

if (
  // Support repos whose entire purpose is to be a Turborepo example, e.g.
  // https://github.com/:username/:my-cool-turborepo-example-repo-name.
  tree === undefined ||
  // Support GitHub URL that ends with a trailing slash, e.g.
  // https://github.com/:username/:my-cool-turborepo-example-repo-name/
  // In this case "t" will be an empty string while the turbo part "_branch" will be undefined
  (tree === "" && sourceBranch === undefined)
) {
  try {
    const infoResponse = await fetchWithTimeout(
      `https://api.github.com/repos/${username}/${name}`
    );
    if (!infoResponse.ok) {
      return;
    }
    const info = (await infoResponse.json()) as { default_branch: string };
    return {
      username,
      name,
      branch: info.default_branch,
      filePath
    } as RepoInfo;
  } catch {
    return;
  }
}

for (const targetSourceFile of this.tsProgram.getSourceFiles()) {
  if (targetSourceFile.isDeclarationFile || ignoreFiles.has(targetSourceFile)) {
    continue;
  }

  if (!forceEmit && this.compiler.incrementalCompilation.safeToSkipEmit(targetSourceFile)) {
    this.compiler.perfRecorder.eventCount(PerfEvent.EmitSkipSourceFile);
    continue;
  }

  this.compiler.perfRecorder.eventCount(PerfEvent.EmitSourceFile);

  emitResults.push(
    emitCallback({
      targetSourceFile,
      program: this.tsProgram,
      host: this.host,
      options: this.options,
      emitOnlyDtsFiles: false,
      writeFile,
      customTransformers: {
        before: beforeTransforms,
        after: customTransforms && customTransforms.afterTs,
        afterDeclarations: afterDeclarationsTransforms,
      } as any,
    }),
  );
}

if (this.isAssignmentOperator(this.next)) {
  const operation = this.next.strValue;

  if (isSafe) {
    this.advance();
    this.error("The '?.' operator cannot be used in the assignment");
  } else {
    const binaryReceiver = new KeyedRead(
      this.span(start),
      this.sourceSpan(start),
      receiver,
      key,
    );
    this.advance();
    const value = this.parseConditional();
    return new Binary(
      this.span(start),
      this.sourceSpan(start),
      operation,
      binaryReceiver,
      value,
    );
  }
} else {
  return isSafe
    ? new SafeKeyedRead(this.span(start), this.sourceSpan(start), receiver, key)
    : new KeyedRead(this.span(start), this.sourceSpan(start), receiver, key);
}

if (locations.has(this.getNodeKey(node.getStart(), node.getWidth()))) {
  // When the entire array needs to be cleared, the diagnostic is
  // reported on the property assignment, rather than an array element.
  if (
    ts.isPropertyAssignment(parent) &&
    parent.name === node &&
    ts.isArrayLiteralExpression(parent.initializer)
  ) {
    result.fullRemovals.add(parent.initializer);
    parent.initializer.elements.forEach((element) => {
      if (ts.isIdentifier(element)) {
        result.allRemovedIdentifiers.add(element.text);
      }
    });
  } else if (ts.isArrayLiteralExpression(parent)) {
    if (!result.partialRemovals.has(parent)) {
      result.partialRemovals.set(parent, new Set());
    }
    result.partialRemovals.get(parent)!.add(node);
    result.allRemovedIdentifiers.add(node.text);
  }
}

if (inject(IS_HYDRATION_DOM_REUSE_ENABLED)) {
  verifySsrContentsIntegrity(doc);
  enableHydrationRuntimeSupport();
} else if (
  typeof ngDevMode !== 'undefined' &&
  ngDevMode &&
  !isClientRenderModeEnabled(doc)
) {
  const console = inject(Console);
  const message = formatRuntimeError(
    RuntimeErrorCode.MISSING_HYDRATION_ANNOTATIONS,
    'Angular hydration was requested on the client, but there was no ' +
      'serialized information present in the server response, ' +
      'thus hydration was not enabled. ' +
      'Make sure the `provideClientHydration()` is included into the list ' +
      'of providers in the server part of the application configuration.',
  );
  console.warn(message);
}

if (releaseTrains.releaseCandidate) {
  docSites.set(releaseTrains.next.branchName, {
    branch: releaseTrains.next.branchName,
    servingUrl: 'https://next.angular.dev/',
  });

  docSites.set(releaseTrains.releaseCandidate.branchName, {
    branch: releaseTrains.releaseCandidate.branchName,
    destination: 'next-angular-dev',
    redirect: {
      from: `v${releaseTrains.releaseCandidate.version.major}-angular-dev`,
      to: 'https://next.angular.dev',
    },
    servingUrl: 'https://next.angular.dev/',
  });
} else {
  docSites.set(releaseTrains.next.branchName, {
    branch: releaseTrains.next.branchName,
    destination: 'next-angular-dev',
    servingUrl: 'https://next.angular.dev/',
  });
}

if (!headersToInclude.includes(headerName) && !warningProduced.has(key)) {
  warningProduced.add(key);
  const truncatedUrl = truncateMiddle(url);

  console.warn(
    formatRuntimeError(
      RuntimeErrorCode.HEADERS_ALTERED_BY_TRANSFER_CACHE,
      `Angular detected that the \`${headerName}\` header is accessed, but the value of the header ` +
        `was not transferred from the server to the client by the HttpTransferCache. ` +
        `To include the value of the \`${headerName}\` header for the \`${truncatedUrl}\` request, ` +
        `use the \`includeHeaders\` list. The \`includeHeaders\` can be defined either ` +
        `on a request level by adding the \`transferCache\` parameter, or on an application ` +
        `level by adding the \`httpCacheTransfer.includeHeaders\` argument to the ` +
        `\`provideClientHydration()\` call. `,
    ),
  );
}

