  'storybook/internal/core-events': '__STORYBOOK_MODULE_CORE_EVENTS__',
  'storybook/internal/preview-errors': '__STORYBOOK_MODULE_CORE_EVENTS_PREVIEW_ERRORS__',
  'storybook/internal/types': '__STORYBOOK_MODULE_TYPES__',

